pre.code:
import { createStore } from 'metaowl'

const store = createStore({
  state: {
    count: 0,
    user: null
  },
  mutations: {
    increment(state) {
      state.count++
    },
    setUser(state, user) {
      state.user = user
    }
  },
  actions: {
    async fetchUser({ commit }) {
      const user = await fetch('/api/user').then(r => r.json())
      commit('setUser', user)
    }
  }
})

// Access state
store.state.count

// Commit mutations
store.commit('increment')

// Dispatch actions
store.dispatch('fetchUser')

import { createStore, createPersistencePlugin } from 'metaowl'

const store = createStore({
  state: { theme: 'light' },
  plugins: [
    createPersistencePlugin({ key: 'app-state' })
  ]
})
